## 什麼是 composable
封裝可重用的 reactive 邏輯、用 `use` 開頭命名。

## 範例：useCounter
```typescript
// composables/useCounter.ts
import { ref, computed } from "vue";

export function useCounter(initial = 0) {
  const count = ref(initial);

  const double = computed(() => count.value * 2);

  function increment() { count.value++; }
  function decrement() { count.value--; }
  function reset() { count.value = initial; }

  return { count, double, increment, decrement, reset };
}
```

## 使用
```vue
<script setup>
import { useCounter } from "@/composables/useCounter";

const { count, double, increment, reset } = useCounter(10);
</script>

<template>
  <div>{{ count }} (x2 = {{ double }})</div>
  <button @click="increment">+</button>
  <button @click="reset">Reset</button>
</template>
```

## 實用範例：useFetch
```typescript
import { ref, watchEffect } from "vue";

export function useFetch<T>(url: () => string) {
  const data = ref<T | null>(null);
  const error = ref<Error | null>(null);
  const loading = ref(false);

  watchEffect(async () => {
    loading.value = true;
    error.value = null;
    try {
      const res = await fetch(url());
      data.value = await res.json();
    } catch (e) {
      error.value = e as Error;
    } finally {
      loading.value = false;
    }
  });

  return { data, error, loading };
}
```

```vue
<script setup>
import { computed } from "vue";
import { useFetch } from "@/composables/useFetch";

const id = ref("1");
const { data, loading, error } = useFetch(() => `/api/users/${id.value}`);
</script>

<template>
  <div v-if="loading">載入中</div>
  <div v-else-if="error">錯誤：{{ error.message }}</div>
  <div v-else>{{ data.name }}</div>
</template>
```

## 實用範例：useLocalStorage
```typescript
import { ref, watch } from "vue";

export function useLocalStorage<T>(key: string, defaultValue: T) {
  const stored = localStorage.getItem(key);
  const value = ref<T>(stored ? JSON.parse(stored) : defaultValue);

  watch(value, (newVal) => {
    localStorage.setItem(key, JSON.stringify(newVal));
  }, { deep: true });

  return value;
}
```

## 實用範例：useDarkMode
```typescript
import { ref, watch } from "vue";

export function useDarkMode() {
  const isDark = ref(matchMedia("(prefers-color-scheme: dark)").matches);

  watch(isDark, (val) => {
    document.documentElement.classList.toggle("dark", val);
  }, { immediate: true });

  return { isDark, toggle: () => isDark.value = !isDark.value };
}
```

