## 需求
- 註冊 / 登入（Supabase Auth）
- CRUD Todo
- 標記完成
- 即時同步多裝置（Realtime）

## 1. 建專案
```bash
npm create vite@latest todo-app -- --template vue-ts
cd todo-app
npm install
npm install pinia vue-router @supabase/supabase-js
npm install -D tailwindcss
```

## 2. Supabase setup
```sql
CREATE TABLE todos (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  done BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE todos ENABLE ROW LEVEL SECURITY;

CREATE POLICY "own_todos" ON todos
FOR ALL USING (auth.uid() = user_id);
```

## 3. Supabase client
```typescript
// src/lib/supabase.ts
import { createClient } from "@supabase/supabase-js";

export const supabase = createClient(
  import.meta.env.VITE_SUPABASE_URL,
  import.meta.env.VITE_SUPABASE_ANON_KEY
);
```

## 4. Pinia store
```typescript
// src/stores/todos.ts
import { defineStore } from "pinia";
import { ref } from "vue";
import { supabase } from "@/lib/supabase";

interface Todo {
  id: string;
  title: string;
  done: boolean;
}

export const useTodosStore = defineStore("todos", () => {
  const todos = ref<Todo[]>([]);

  async function load() {
    const { data } = await supabase
      .from("todos")
      .select("*")
      .order("created_at", { ascending: false });
    todos.value = data || [];
  }

  async function add(title: string) {
    const { data: { user } } = await supabase.auth.getUser();
    const { data } = await supabase
      .from("todos")
      .insert({ title, user_id: user!.id })
      .select()
      .single();
    if (data) todos.value.unshift(data);
  }

  async function toggle(id: string) {
    const todo = todos.value.find(t => t.id === id);
    if (!todo) return;
    todo.done = !todo.done;
    await supabase.from("todos").update({ done: todo.done }).eq("id", id);
  }

  async function remove(id: string) {
    todos.value = todos.value.filter(t => t.id !== id);
    await supabase.from("todos").delete().eq("id", id);
  }

  function subscribe() {
    return supabase
      .channel("todos")
      .on("postgres_changes",
        { event: "*", schema: "public", table: "todos" },
        () => load())
      .subscribe();
  }

  return { todos, load, add, toggle, remove, subscribe };
});
```

## 5. Auth 頁
```vue
<!-- src/views/Login.vue -->
<script setup lang="ts">
import { ref } from "vue";
import { useRouter } from "vue-router";
import { supabase } from "@/lib/supabase";

const email = ref("");
const password = ref("");
const router = useRouter();

async function signIn() {
  const { error } = await supabase.auth.signInWithPassword({
    email: email.value, password: password.value
  });
  if (!error) router.push("/");
}

async function signUp() {
  const { error } = await supabase.auth.signUp({
    email: email.value, password: password.value
  });
  if (!error) alert("檢查 email 完成註冊");
}
</script>

<template>
  <div class="max-w-md mx-auto p-6">
    <h1 class="text-2xl mb-4">登入 / 註冊</h1>
    <input v-model="email" type="email" placeholder="Email" class="block w-full p-2 mb-2 border rounded">
    <input v-model="password" type="password" placeholder="密碼" class="block w-full p-2 mb-4 border rounded">
    <button @click="signIn" class="bg-green-500 text-white px-4 py-2 rounded mr-2">登入</button>
    <button @click="signUp" class="bg-blue-500 text-white px-4 py-2 rounded">註冊</button>
  </div>
</template>
```

## 6. Todo 頁
```vue
<!-- src/views/Todos.vue -->
<script setup lang="ts">
import { ref, onMounted, onUnmounted } from "vue";
import { useTodosStore } from "@/stores/todos";

const store = useTodosStore();
const newTitle = ref("");
let unsub: any;

onMounted(async () => {
  await store.load();
  unsub = store.subscribe();
});

onUnmounted(() => unsub?.unsubscribe());

function handleAdd() {
  if (!newTitle.value.trim()) return;
  store.add(newTitle.value);
  newTitle.value = "";
}
</script>

<template>
  <div class="max-w-2xl mx-auto p-6">
    <h1 class="text-3xl font-bold mb-6">📝 My Todos</h1>

    <form @submit.prevent="handleAdd" class="flex gap-2 mb-6">
      <input
        v-model="newTitle"
        placeholder="新增 todo..."
        class="flex-1 p-2 border rounded"
      >
      <button type="submit" class="bg-green-500 text-white px-4 py-2 rounded">
        +
      </button>
    </form>

    <ul class="space-y-2">
      <li
        v-for="todo in store.todos"
        :key="todo.id"
        class="flex items-center gap-2 p-3 border rounded"
      >
        <input
          type="checkbox"
          :checked="todo.done"
          @change="store.toggle(todo.id)"
        >
        <span :class="{ 'line-through text-gray-400': todo.done }">
          {{ todo.title }}
        </span>
        <button @click="store.remove(todo.id)" class="ml-auto text-red-500">
          ×
        </button>
      </li>
    </ul>
  </div>
</template>
```

## 7. Router
```typescript
// src/router/index.ts
import { createRouter, createWebHistory } from "vue-router";
import { supabase } from "@/lib/supabase";

const router = createRouter({
  history: createWebHistory(),
  routes: [
    { path: "/", component: () => import("@/views/Todos.vue"), meta: { requiresAuth: true } },
    { path: "/login", component: () => import("@/views/Login.vue") },
  ],
});

router.beforeEach(async (to) => {
  const { data: { user } } = await supabase.auth.getUser();
  if (to.meta.requiresAuth && !user) return "/login";
  if (to.path === "/login" && user) return "/";
});

export default router;
```

